int read_file(struct file *f, char *buf, size_t len)
{
	char *tmp;
	int err;

	if (!f->f_op->read)
		return -EINVAL;

	tmp = kmalloc(len, GFP_KERNEL);
	if (!tmp)
		return -ENOMEM;

	err = f->f_op->read(f, tmp, len);
	if (err < 0)
		goto out_free;

	memcpy(buf, tmp, err);
out_free:
	kfree(tmp);
	return err;
}
